('1c566de4-9c61-43a4-8969-a1dcaf93dc6c', '04b0ccc5-17b2-479f-bc4a-a1d17847e4c1', 'QUIZ', 6, '{\"questions\":[{\"question\":\"Nghĩa của từ \\\"岁\\\" (suì) là gì?\",\"options\":[\"chúng tôi\",\"mở, khởi động\",\"tuổi\",\"đồ vật, thứ\"],\"correct\":\"tuổi\"},{\"question\":\"Nghĩa của từ \\\"儿子\\\" (érzi) là gì?\",\"options\":[\"con trai\",\"xem\",\"cái gì\",\"bây giờ\"],\"correct\":\"con trai\"},{\"question\":\"Nghĩa của từ \\\"开\\\" (kāi) là gì?\",\"options\":[\"sẽ, biết (kỹ năng)\",\"năm\",\"hai\",\"mở, khởi động\"],\"correct\":\"mở, khởi động\"},{\"question\":\"Nghĩa của từ \\\"回\\\" (huí) là gì?\",\"options\":[\"quay lại, về\",\"mưa\",\"nhìn thấy\",\"cuốn (dùng cho sách)\"],\"correct\":\"quay lại, về\"},{\"question\":\"Nghĩa của từ \\\"茶\\\" (chá) là gì?\",\"options\":[\"đều\",\"yêu\",\"ga tàu\",\"trà\"],\"correct\":\"trà\"},{\"question\":\"Nghĩa của từ \\\"好\\\" (hǎo) là gì?\",\"options\":[\"ba\",\"miếng, đồng (tiền)\",\"tám\",\"tốt, khỏe\"],\"correct\":\"tốt, khỏe\"},{\"question\":\"Nghĩa của từ \\\"妈妈\\\" (māma) là gì?\",\"options\":[\"mẹ\",\"xuống\",\"tiền\",\"lạnh\"],\"correct\":\"mẹ\"},{\"question\":\"Nghĩa của từ \\\"电影\\\" (diànyǐng) là gì?\",\"options\":[\"gọi, tên gọi\",\"lên\",\"phim\",\"sẽ, biết (kỹ năng)\"],\"correct\":\"phim\"},{\"question\":\"Nghĩa của từ \\\"和\\\" (hé) là gì?\",\"options\":[\"không sao, không có gì\",\"quen biết\",\"và\",\"phim\"],\"correct\":\"và\"},{\"question\":\"Nghĩa của từ \\\"年\\\" (nián) là gì?\",\"options\":[\"đi\",\"đọc\",\"gọi điện thoại\",\"năm\"],\"correct\":\"năm\"},{\"question\":\"Nghĩa của từ \\\"零\\\" (líng) là gì?\",\"options\":[\"quay lại, về\",\"không (số 0)\",\"công việc\",\"đẹp\"],\"correct\":\"không (số 0)\"},{\"question\":\"Nghĩa của từ \\\"哪里 (哪儿)\\\" (nǎlǐ (nǎr)) là gì?\",\"options\":[\"đâu, chỗ nào\",\"buổi chiều\",\"xuống\",\"máy tính\"],\"correct\":\"đâu, chỗ nào\"},{\"question\":\"Nghĩa của từ \\\"爸爸\\\" (bàba) là gì?\",\"options\":[\"bố\",\"con trai\",\"nói chuyện\",\"lớn, to\"],\"correct\":\"bố\"},{\"question\":\"Nghĩa của từ \\\"喝\\\" (hē) là gì?\",\"options\":[\"gọi điện thoại\",\"cơm\",\"mở, khởi động\",\"uống\"],\"correct\":\"uống\"},{\"question\":\"Nghĩa của từ \\\"没关系\\\" (méi guānxi) là gì?\",\"options\":[\"buổi chiều\",\"bố\",\"cốc\",\"không sao, không có gì\"],\"correct\":\"không sao, không có gì\"},{\"question\":\"Nghĩa của từ \\\"字\\\" (zì) là gì?\",\"options\":[\"bệnh viện\",\"chữ\",\"trong\",\"gia đình, nhà\"],\"correct\":\"chữ\"},{\"question\":\"Nghĩa của từ \\\"苹果\\\" (píngguǒ) là gì?\",\"options\":[\"táo\",\"phía sau\",\"trà\",\"máy bay\"],\"correct\":\"táo\"},{\"question\":\"Nghĩa của từ \\\"汉语\\\" (Hànyǔ) là gì?\",\"options\":[\"quen biết\",\"tiếng Hán\",\"một\",\"bạn\"],\"correct\":\"tiếng Hán\"},{\"question\":\"Nghĩa của từ \\\"对不起\\\" (duìbùqǐ) là gì?\",\"options\":[\"học tập\",\"xin lỗi\",\"ga tàu\",\"yêu\"],\"correct\":\"xin lỗi\"},{\"question\":\"Nghĩa của từ \\\"钱\\\" (qián) là gì?\",\"options\":[\"như thế nào\",\"tiền\",\"năm\",\"Trung Quốc\"],\"correct\":\"tiền\"}]}');
