('35ed1171-d96c-4d30-8506-336dfd858b72', '287cfb06-a581-4d7e-a467-a2733c109326', 'GRAMMAR', 4, '{\"rule\":\"Cấu trúc Chủ ngữ (S) + Động từ (V) + Tân ngữ (O)\",\"examples\":[{\"text\":\"I study English.\",\"phonetic\":\"aɪ ˈstʌdi ˈɪŋglɪʃ.\",\"meaning\":\"Tôi học tiếng Anh.\"},{\"text\":\"He likes drinking tea.\",\"phonetic\":\"hiː laɪks ˈdrɪŋkɪŋ tiː.\",\"meaning\":\"Anh ấy thích uống trà.\"}]}'),
('4191c6bd-14d7-4d8a-bd7f-848887bad60c', '287cfb06-a581-4d7e-a467-a2733c109326', 'READING', 5, '{\"paragraphs\":[{\"text\":\"Good morning! My name is Alex. I am from the United States. I am currently studying at Oxford University.\",\"phonetic\":\"gʊd ˈmɔːnɪŋ! maɪ neɪm ɪz ˈælɪks. aɪ æm frɒm ðə jʊˈnaɪtɪd steɪts. aɪ æm ˈkʌrəntli ˈstʌdyɪŋ æt ˈɒksfəd ˌjuːnɪˈvɜːsɪti.\",\"meaning\":\"Chào buổi sáng! Tên tôi là Alex. Tôi đến từ Hoa Kỳ. Hiện tại tôi đang học tại Đại học Oxford.\"},{\"text\":\"My hobbies are reading books and listening to music. How about you?\",\"phonetic\":\"maɪ ˈhɒbiz ɑː ˈriːdɪŋ bʊks ænd ˈlɪsnɪŋ tuː ˈmjuːzɪk. haʊ əˈbaʊt juː?\",\"meaning\":\"Sở thích của tôi là đọc sách và nghe nhạc. Còn bạn thì sao?\"}]}'),
('5ac66f36-c0ab-4299-a6a9-a11361e2c169', '27f02e6d-e186-4a6b-a88d-1af1cf4d715d', 'GRAMMAR', 3, '{\"rule\":\"Ngữ pháp căn bản\",\"examples\":[]}'),
('5d363f26-c27a-4539-b6ac-0bc9478c89a8', '287cfb06-a581-4d7e-a467-a2733c109326', 'FLASHCARD', 2, '{\"cards\":[{\"term\":\"Hello\",\"phonetic\":\"həˈləʊ\",\"meaning\":\"Xin chào\"},{\"term\":\"Thank you\",\"phonetic\":\"θæŋk juː\",\"meaning\":\"Cảm ơn\"},{\"term\":\"Sorry\",\"phonetic\":\"ˈsɒri\",\"meaning\":\"Xin lỗi\"},{\"term\":\"Welcome\",\"phonetic\":\"ˈwɛlkəm\",\"meaning\":\"Chào mừng\"}]}'),
('7beb2ffb-aa91-426f-9652-63d6b3b58e81', '27f02e6d-e186-4a6b-a88d-1af1cf4d715d', 'SENTENCE', 4, '{\"sentences\":[{\"text\":\"阿姨非常喜欢我们。\",\"meaning\":\"Dì rất thích chúng tôi.\",\"phonetic\":\"Āyí fēicháng xǐhuān wǒmen.\",\"audio_url\":\"\"},{\"text\":\"啊，我忘记了！\",\"meaning\":\"À, tôi quên rồi!\",\"phonetic\":\"A, wǒ wàngjì le!\",\"audio_url\":\"\"},{\"text\":\"他比我矮。\",\"meaning\":\"Anh ấy thấp hơn tôi.\",\"phonetic\":\"Tā bǐ wǒ ǎi.\",\"audio_url\":\"\"},{\"text\":\"我的爱好是画画儿。\",\"meaning\":\"Sở thích của tôi là vẽ tranh.\",\"phonetic\":\"Wǒ de àihào shì huà huàr.\",\"audio_url\":\"\"},{\"text\":\"请保持安静。\",\"meaning\":\"Xin hãy giữ yên lặng.\",\"phonetic\":\"Qǐng bǎochí ānjìng.\",\"audio_url\":\"\"},{\"text\":\"把书给我。\",\"meaning\":\"Đưa cuốn sách cho tôi.\",\"phonetic\":\"Bǎ shū gěi wǒ.\",\"audio_url\":\"\"},{\"text\":\"我们班有二十个学生。\",\"meaning\":\"Lớp chúng tôi có hai mươi học sinh.\",\"phonetic\":\"Wǒmen bān yǒu èrshí gè xuéshēng.\",\"audio_url\":\"\"},{\"text\":\"他搬家到北京了。\",\"meaning\":\"Anh ấy đã chuyển nhà đến Bắc Kinh.\",\"phonetic\":\"Tā bānjiā dào Běijīng le.\",\"audio_url\":\"\"},{\"text\":\"我们半个小时后见。\",\"meaning\":\"Chúng ta gặp nhau sau nửa giờ.\",\"phonetic\":\"Wǒmen bàn gè xiǎoshí hòu jiàn.\",\"audio_url\":\"\"},{\"text\":\"我有一个好办法。\",\"meaning\":\"Tôi có một cách hay.\",\"phonetic\":\"Wǒ yǒu yīgè hǎo bànfǎ.\",\"audio_url\":\"\"},{\"text\":\"他在办公室工作。\",\"meaning\":\"Anh ấy làm việc ở văn phòng.\",\"phonetic\":\"Tā zài bàngōngshì gōngzuò.\",\"audio_url\":\"\"},{\"text\":\"有你帮忙我就放心了。\",\"meaning\":\"Có bạn giúp thì tôi yên tâm rồi.\",\"phonetic\":\"Yǒu nǐ bāngmáng wǒ jiù fàngxīn le.\",\"audio_url\":\"\"},{\"text\":\"我的包丢了。\",\"meaning\":\"Cái túi của tôi bị mất rồi.\",\"phonetic\":\"Wǒ de bāo diū le.\",\"audio_url\":\"\"},{\"text\":\"我吃饱了。\",\"meaning\":\"Tôi ăn no rồi.\",\"phonetic\":\"Wǒ chī bǎo le.\",\"audio_url\":\"\"},{\"text\":\"北方的冬天很冷。\",\"meaning\":\"Mùa đông ở phía Bắc rất lạnh.\",\"phonetic\":\"Běifāng de dōngtiān hěn lěng.\",\"audio_url\":\"\"},{\"text\":\"他被老师表扬了。\",\"meaning\":\"Anh ấy được thầy giáo khen ngợi.\",\"phonetic\":\"Tā bèi lǎoshī biǎoyáng le.\",\"audio_url\":\"\"},{\"text\":\"她比较高。\",\"meaning\":\"Cô ấy khá cao.\",\"phonetic\":\"Tā bǐjiào gāo.\",\"audio_url\":\"\"},{\"text\":\"他们在参加比赛。\",\"meaning\":\"Họ đang tham gia thi đấu.\",\"phonetic\":\"Tāmen zài cānjiā bǐsài.\",\"audio_url\":\"\"},{\"text\":\"你必须按时到。\",\"meaning\":\"Bạn phải đến đúng giờ.\",\"phonetic\":\"Nǐ bìxū ànshí dào.\",\"audio_url\":\"\"},{\"text\":\"这里的天气变化很大。\",\"meaning\":\"Thời tiết ở đây thay đổi rất nhiều.\",\"phonetic\":\"Zhèlǐ de tiānqì biànhuà hěn dà.\",\"audio_url\":\"\"},{\"text\":\"他表示同意这个计划。\",\"meaning\":\"Anh ấy thể hiện đồng ý với kế hoạch này.\",\"phonetic\":\"Tā biǎoshì tóngyì zhège jìhuà.\",\"audio_url\":\"\"},{\"text\":\"她在表演节目。\",\"meaning\":\"Cô ấy đang biểu diễn chương trình.\",\"phonetic\":\"Tā zài biǎoyǎn jiémù.\",\"audio_url\":\"\"},{\"text\":\"别人的意见很重要。\",\"meaning\":\"Ý kiến của người khác rất quan trọng.\",\"phonetic\":\"Biérén de yìjiàn hěn zhòngyào.\",\"audio_url\":\"\"},{\"text\":\"宾馆的房间很干净。\",\"meaning\":\"Phòng của khách sạn rất sạch sẽ.\",\"phonetic\":\"Bīnguǎn de fángjiān hěn gānjìng.\",\"audio_url\":\"\"},{\"text\":\"冰箱里有很多食物。\",\"meaning\":\"Trong tủ lạnh có rất nhiều thức ăn.\",\"phonetic\":\"Bīngxiāng lǐ yǒu hěn duō shíwù.\",\"audio_url\":\"\"},{\"text\":\"为什么你现在才来。\",\"meaning\":\"Tại sao bây giờ bạn mới tới?\",\"phonetic\":\"Wèi shénme nǐ xiànzài cái lái?\",\"audio_url\":\"\"},{\"text\":\"菜单上有很多菜。\",\"meaning\":\"Trên thực đơn có nhiều món ăn.\",\"phonetic\":\"Càidān shàng yǒu hěn duō cài.\",\"audio_url\":\"\"},{\"text\":\"我参加了这个活动。\",\"meaning\":\"Tôi đã tham gia hoạt động này.\",\"phonetic\":\"Wǒ cānjiā le zhège huódòng.\",\"audio_url\":\"\"},{\"text\":\"草地上有很多花。\",\"meaning\":\"Trên bãi cỏ có nhiều hoa.\",\"phonetic\":\"Cǎodì shàng yǒu hěn duō huā.\",\"audio_url\":\"\"},{\"text\":\"我住在三层。\",\"meaning\":\"Tôi sống ở tầng ba.\",\"phonetic\":\"Wǒ zhù zài sān céng.\",\"audio_url\":\"\"},{\"text\":\"今天的天气很差。\",\"meaning\":\"Thời tiết hôm nay rất tệ.\",\"phonetic\":\"Jīntiān de tiānqì hěn chà.\",\"audio_url\":\"\"},{\"text\":\"我去超市买东西。\",\"meaning\":\"Tôi đi siêu thị mua đồ.\",\"phonetic\":\"Wǒ qù chāoshì mǎi dōngxi.\",\"audio_url\":\"\"},{\"text\":\"他穿了一件白衬衫。\",\"meaning\":\"Anh ấy mặc một chiếc áo sơ mi trắng.\",\"phonetic\":\"Tā chuān le yī jiàn bái chènshān.\",\"audio_url\":\"\"},{\"text\":\"他的成绩很好。\",\"meaning\":\"Thành tích của anh ấy rất tốt.\",\"phonetic\":\"Tā de chéngjī hěn hǎo.\",\"audio_url\":\"\"},{\"text\":\"这座城市很大。\",\"meaning\":\"Thành phố này rất lớn.\",\"phonetic\":\"Zhè zuò chéngshì hěn dà.\",\"audio_url\":\"\"},{\"text\":\"他今天迟到了。\",\"meaning\":\"Hôm nay anh ấy đến muộn.\",\"phonetic\":\"Tā jīntiān chídào le.\",\"audio_url\":\"\"},{\"text\":\"我们出现了问题。\",\"meaning\":\"Chúng tôi gặp vấn đề rồi.\",\"phonetic\":\"Wǒmen chūxiàn le wèntí.\",\"audio_url\":\"\"},{\"text\":\"厨房很干净。\",\"meaning\":\"Nhà bếp rất sạch.\",\"phonetic\":\"Chúfáng hěn gānjìng.\",\"audio_url\":\"\"},{\"text\":\"除了他，大家都来了。\",\"meaning\":\"Ngoài anh ấy, mọi người đều đến.\",\"phonetic\":\"Chúle tā, dàjiā dōu lái le.\",\"audio_url\":\"\"},{\"text\":\"春天来了，花开了。\",\"meaning\":\"Mùa xuân đến rồi, hoa nở rồi.\",\"phonetic\":\"Chūntiān lái le, huā kāi le.\",\"audio_url\":\"\"},{\"text\":\"我喜欢学习新词语。\",\"meaning\":\"Tôi thích học từ mới.\",\"phonetic\":\"Wǒ xǐhuān xuéxí xīn cíyǔ.\",\"audio_url\":\"\"},{\"text\":\"她很聪明，总是知道答案。\",\"meaning\":\"Cô ấy rất thông minh, luôn biết đáp án.\",\"phonetic\":\"Tā hěn cōngmíng, zǒng shì zhīdào dá\'àn.\",\"audio_url\":\"\"},{\"text\":\"我们一起打扫房间吧。\",\"meaning\":\"Chúng ta cùng dọn phòng nhé.\",\"phonetic\":\"Wǒmen yīqǐ dǎsǎo fángjiān ba.\",\"audio_url\":\"\"},{\"text\":\"我打算去旅游。\",\"meaning\":\"Tôi dự định đi du lịch.\",\"phonetic\":\"Wǒ dǎsuàn qù lǚyóu.\",\"audio_url\":\"\"},{\"text\":\"别忘了带雨伞。\",\"meaning\":\"Đừng quên mang theo ô.\",\"phonetic\":\"Bié wàngle dài yǔsǎn.\",\"audio_url\":\"\"},{\"text\":\"我担心他的健康。\",\"meaning\":\"Tôi lo lắng cho sức khỏe của anh ấy.\",\"phonetic\":\"Wǒ dānxīn tā de jiànkāng.\",\"audio_url\":\"\"},{\"text\":\"生日快乐，给你蛋糕。\",\"meaning\":\"Sinh nhật vui vẻ, tặng bạn bánh ngọt.\",\"phonetic\":\"Shēngrì kuàilè, gěi nǐ dàngāo.\",\"audio_url\":\"\"},{\"text\":\"你当然可以去。\",\"meaning\":\"Đương nhiên bạn có thể đi.\",\"phonetic\":\"Nǐ dāngrán kěyǐ qù.\",\"audio_url\":\"\"},{\"text\":\"请慢慢地说。\",\"meaning\":\"Xin hãy nói chậm lại.\",\"phonetic\":\"Qǐng mànmàn de shuō.\",\"audio_url\":\"\"},{\"text\":\"请开灯。\",\"meaning\":\"Vui lòng bật đèn.\",\"phonetic\":\"Qǐng kāi dēng.\",\"audio_url\":\"\"},{\"text\":\"他的声音很低。\",\"meaning\":\"Giọng anh ấy rất nhỏ.\",\"phonetic\":\"Tā de shēngyīn hěn dī.\",\"audio_url\":\"\"},{\"text\":\"这个地方很好玩。\",\"meaning\":\"Nơi này rất vui.\",\"phonetic\":\"Zhège dìfāng hěn hǎowán.\",\"audio_url\":\"\"},{\"text\":\"我坐地铁去上班。\",\"meaning\":\"Tôi đi làm bằng tàu điện ngầm.\",\"phonetic\":\"Wǒ zuò dìtiě qù shàngbān.\",\"audio_url\":\"\"},{\"text\":\"你有这座城市的地图吗？\",\"meaning\":\"Bạn có bản đồ của thành phố này không?\",\"phonetic\":\"Nǐ yǒu zhè zuò chéngshì de dìtú ma?\",\"audio_url\":\"\"},{\"text\":\"我们坐电梯上楼。\",\"meaning\":\"Chúng tôi đi thang máy lên lầu.\",\"phonetic\":\"Wǒmen zuò diàntī shàng lóu.\",\"audio_url\":\"\"},{\"text\":\"请发电子邮件给我。\",\"meaning\":\"Xin gửi email cho tôi.\",\"phonetic\":\"Qǐng fā diànzǐ yóujiàn gěi wǒ.\",\"audio_url\":\"\"},{\"text\":\"东边有一座山。\",\"meaning\":\"Phía đông có một ngọn núi.\",\"phonetic\":\"Dōngbiān yǒu yī zuò shān.\",\"audio_url\":\"\"},{\"text\":\"冬天很冷。\",\"meaning\":\"Mùa đông rất lạnh.\",\"phonetic\":\"Dōngtiān hěn lěng.\",\"audio_url\":\"\"},{\"text\":\"我喜欢动物。\",\"meaning\":\"Tôi thích động vật.\",\"phonetic\":\"Wǒ xǐhuān dòngwù.\",\"audio_url\":\"\"},{\"text\":\"这条裙子太短了。\",\"meaning\":\"Chiếc váy này quá ngắn.\",\"phonetic\":\"Zhè tiáo qúnzi tài duǎn le.\",\"audio_url\":\"\"},{\"text\":\"他讲了一段故事。\",\"meaning\":\"Anh ấy đã kể một đoạn câu chuyện.\",\"phonetic\":\"Tā jiǎng le yī duàn gùshì.\",\"audio_url\":\"\"},{\"text\":\"我每天锻炼身体。\",\"meaning\":\"Tôi tập thể dục mỗi ngày.\",\"phonetic\":\"Wǒ měitiān duànliàn shēntǐ.\",\"audio_url\":\"\"},{\"text\":\"这里的景色多么美丽。\",\"meaning\":\"Cảnh ở đây đẹp làm sao.\",\"phonetic\":\"Zhèlǐ de jǐngsè duōme měilì.\",\"audio_url\":\"\"},{\"text\":\"我饿了，想吃饭。\",\"meaning\":\"Tôi đói rồi, muốn ăn cơm.\",\"phonetic\":\"Wǒ è le, xiǎng chī fàn.\",\"audio_url\":\"\"},{\"text\":\"他聪明而且很努力。\",\"meaning\":\"Anh ấy thông minh hơn nữa rất chăm chỉ.\",\"phonetic\":\"Tā cōngmíng érqiě hěn nǔlì.\",\"audio_url\":\"\"},{\"text\":\"我的耳朵很敏感。\",\"meaning\":\"Tai tôi rất nhạy cảm.\",\"phonetic\":\"Wǒ de ěrduo hěn mǐngǎn.\",\"audio_url\":\"\"},{\"text\":\"他发烧了，要休息。\",\"meaning\":\"Anh ấy bị sốt, cần nghỉ ngơi.\",\"phonetic\":\"Tā fāshāo le, yào xiūxí.\",\"audio_url\":\"\"},{\"text\":\"我发现了一个秘密。\",\"meaning\":\"Tôi đã phát hiện ra một bí mật.\",\"phonetic\":\"Wǒ fāxiàn le yīgè mìmì.\",\"audio_url\":\"\"},{\"text\":\"这里很方便。\",\"meaning\":\"Ở đây rất tiện lợi.\",\"phonetic\":\"Zhèlǐ hěn fāngbiàn.\",\"audio_url\":\"\"},{\"text\":\"请把书放在桌子上。\",\"meaning\":\"Vui lòng để sách lên bàn.\",\"phonetic\":\"Qǐng bǎ shū fàng zài zhuōzi shàng.\",\"audio_url\":\"\"},{\"text\":\"请你放心。\",\"meaning\":\"Xin bạn yên tâm.\",\"phonetic\":\"Qǐng nǐ fàngxīn.\",\"audio_url\":\"\"},{\"text\":\"我们八点十分出发。\",\"meaning\":\"Chúng ta khởi hành lúc tám giờ mười phút.\",\"phonetic\":\"Wǒmen bā diǎn shí fēn chūfā.\",\"audio_url\":\"\"},{\"text\":\"我家附近有公园。\",\"meaning\":\"Gần nhà tôi có công viên.\",\"phonetic\":\"Wǒ jiā fùjìn yǒu gōngyuán.\",\"audio_url\":\"\"},{\"text\":\"我需要复习功课。\",\"meaning\":\"Tôi cần ôn bài.\",\"phonetic\":\"Wǒ xūyào fùxí gōngkè.\",\"audio_url\":\"\"},{\"text\":\"房间很干净。\",\"meaning\":\"Phòng rất sạch sẽ.\",\"phonetic\":\"Fángjiān hěn gānjìng.\",\"audio_url\":\"\"},{\"text\":\"我敢说你是对的。\",\"meaning\":\"Tôi dám nói bạn đúng.\",\"phonetic\":\"Wǒ gǎn shuō nǐ shì duì de.\",\"audio_url\":\"\"},{\"text\":\"他感冒了，不能来。\",\"meaning\":\"Anh ấy bị cảm, không thể đến.\",\"phonetic\":\"Tā gǎnmào le, bùnéng lái.\",\"audio_url\":\"\"},{\"text\":\"刚才我看见他了。\",\"meaning\":\"Vừa rồi tôi đã nhìn thấy anh ấy.\",\"phonetic\":\"Gāngcái wǒ kànjiàn tā le.\",\"audio_url\":\"\"},{\"text\":\"我跟他一起去。\",\"meaning\":\"Tôi đi cùng anh ấy.\",\"phonetic\":\"Wǒ gēn tā yīqǐ qù.\",\"audio_url\":\"\"},{\"text\":\"根据天气预报，今天会下雨。\",\"meaning\":\"Theo dự báo thời tiết, hôm nay sẽ mưa.\",\"phonetic\":\"Gēnjù tiānqì yùbào, jīntiān huì xiàyǔ.\",\"audio_url\":\"\"},{\"text\":\"她比我更高。\",\"meaning\":\"Cô ấy cao hơn tôi.\",\"phonetic\":\"Tā bǐ wǒ gèng gāo.\",\"audio_url\":\"\"},{\"text\":\"我喜欢去公园散步。\",\"meaning\":\"Tôi thích đi dạo trong công viên.\",\"phonetic\":\"Wǒ xǐhuān qù gōngyuán sànbù.\",\"audio_url\":\"\"},{\"text\":\"这个故事很有趣。\",\"meaning\":\"Câu chuyện này rất thú vị.\",\"phonetic\":\"Zhège gùshì hěn yǒuqù.\",\"audio_url\":\"\"},{\"text\":\"今天刮风了。\",\"meaning\":\"Hôm nay gió thổi mạnh.\",\"phonetic\":\"Jīntiān guāfēng le.\",\"audio_url\":\"\"},{\"text\":\"请关门。\",\"meaning\":\"Vui lòng đóng cửa.\",\"phonetic\":\"Qǐng guān mén.\",\"audio_url\":\"\"},{\"text\":\"我们是好朋友，关系很好。\",\"meaning\":\"Chúng tôi là bạn tốt, quan hệ rất tốt.\",\"phonetic\":\"Wǒmen shì hǎo péngyǒu, guānxì hěn hǎo.\",\"audio_url\":\"\"},{\"text\":\"她很关心我。\",\"meaning\":\"Cô ấy rất quan tâm đến tôi.\",\"phonetic\":\"Tā hěn guānxīn wǒ.\",\"audio_url\":\"\"},{\"text\":\"这是关于旅行的书。\",\"meaning\":\"Đây là cuốn sách về du lịch.\",\"phonetic\":\"Zhè shì guānyú lǚxíng de shū.\",\"audio_url\":\"\"},{\"text\":\"我爱我的国家。\",\"meaning\":\"Tôi yêu đất nước của tôi.\",\"phonetic\":\"Wǒ ài wǒ de guójiā.\",\"audio_url\":\"\"},{\"text\":\"请给我一杯果汁。\",\"meaning\":\"Vui lòng cho tôi một ly nước ép.\",\"phonetic\":\"Qǐng gěi wǒ yī bēi guǒzhī.\",\"audio_url\":\"\"},{\"text\":\"我们过去是同学。\",\"meaning\":\"Chúng tôi từng là bạn học.\",\"phonetic\":\"Wǒmen guòqù shì tóngxué.\",\"audio_url\":\"\"},{\"text\":\"你还是学生吗？\",\"meaning\":\"Bạn vẫn là học sinh à?\",\"phonetic\":\"Nǐ háishì xuéshēng ma?\",\"audio_url\":\"\"},{\"text\":\"我害怕黑暗。\",\"meaning\":\"Tôi s