eaning\":\"Anh ấy đã mua một chiếc quần.\",\"phonetic\":\"Tā mǎi le yī tiáo kùzi.\",\"audio_url\":\"\"},{\"text\":\"他是我的同事。\",\"meaning\":\"Anh ấy là đồng nghiệp của tôi.\",\"phonetic\":\"Tā shì wǒ de tóngshì.\",\"audio_url\":\"\"},{\"text\":\"我同意你的看法。\",\"meaning\":\"Tôi đồng ý với quan điểm của bạn.\",\"phonetic\":\"Wǒ tóngyì nǐ de kànfǎ.\",\"audio_url\":\"\"},{\"text\":\"她的头发很长。\",\"meaning\":\"Tóc của cô ấy rất dài.\",\"phonetic\":\"Tā de tóufa hěn cháng.\",\"audio_url\":\"\"},{\"text\":\"他突然离开了。\",\"meaning\":\"Anh ấy đột nhiên rời đi.\",\"phonetic\":\"Tā tūrán líkāi le.\",\"audio_url\":\"\"},{\"text\":\"我们去图书馆看书吧。\",\"meaning\":\"Chúng ta đến thư viện đọc sách nhé.\",\"phonetic\":\"Wǒmen qù túshūguǎn kànshū ba.\",\"audio_url\":\"\"},{\"text\":\"他的腿很长。\",\"meaning\":\"Chân của anh ấy rất dài.\",\"phonetic\":\"Tā de tuǐ hěn cháng.\",\"audio_url\":\"\"},{\"text\":\"我完成了作业。\",\"meaning\":\"Tôi đã hoàn thành bài tập.\",\"phonetic\":\"Wǒ wánchéng le zuòyè.\",\"audio_url\":\"\"},{\"text\":\"他吃了三碗饭。\",\"meaning\":\"Anh ấy đã ăn ba bát cơm.\",\"phonetic\":\"Tā chī le sān wǎn fàn.\",\"audio_url\":\"\"},{\"text\":\"一万个人参加了比赛。\",\"meaning\":\"Mười nghìn người đã tham gia cuộc thi.\",\"phonetic\":\"Yī wàn gè rén cānjiā le bǐsài.\",\"audio_url\":\"\"},{\"text\":\"请不要忘记带书。\",\"meaning\":\"Vui lòng đừng quên mang sách.\",\"phonetic\":\"Qǐng bùyào wàngjì dài shū.\",\"audio_url\":\"\"},{\"text\":\"请坐在这位先生旁边。\",\"meaning\":\"Xin ngồi bên cạnh ông này.\",\"phonetic\":\"Qǐng zuò zài zhè wèi xiānshēng pángbiān.\",\"audio_url\":\"\"},{\"text\":\"我为你感到骄傲。\",\"meaning\":\"Tôi tự hào về bạn.\",\"phonetic\":\"Wǒ wèi nǐ gǎndào jiāo\'ào.\",\"audio_url\":\"\"},{\"text\":\"我来中国是为了学习汉语。\",\"meaning\":\"Tôi đến Trung Quốc để học tiếng Trung.\",\"phonetic\":\"Wǒ lái Zhōngguó shì wèile xuéxí hànyǔ .\",\"audio_url\":\"\"},{\"text\":\"他对中国文化很感兴趣。\",\"meaning\":\"Anh ấy rất quan tâm đến văn hóa Trung Quốc.\",\"phonetic\":\"Tā duì Zhōngguó wénhuà hěn gǎn xìngqù.\",\"audio_url\":\"\"},{\"text\":\"我住在西边。\",\"meaning\":\"Tôi sống ở phía tây.\",\"phonetic\":\"Wǒ zhù zài xībiān.\",\"audio_url\":\"\"},{\"text\":\"他习惯早起。\",\"meaning\":\"Anh ấy quen dậy sớm.\",\"phonetic\":\"Tā xíguàn zǎoqǐ.\",\"audio_url\":\"\"},{\"text\":\"洗手间在那边。\",\"meaning\":\"Nhà vệ sinh ở đằng kia.\",\"phonetic\":\"Xǐshǒujiān zài nà biān.\",\"audio_url\":\"\"},{\"text\":\"我每天早上都洗澡。\",\"meaning\":\"Tôi đều tắm vào mỗi buổi sáng.\",\"phonetic\":\"Wǒ měitiān zǎoshang dōu xǐzǎo.\",\"audio_url\":\"\"},{\"text\":\"我喜欢这个颜色。\",\"meaning\":\"Tôi thích màu này.\",\"phonetic\":\"Wǒ xǐhuān zhège yánsè.\",\"audio_url\":\"\"},{\"text\":\"现在是八点。\",\"meaning\":\"Bây giờ là tám giờ.\",\"phonetic\":\"Xiànzài shì bā diǎn.\",\"audio_url\":\"\"},{\"text\":\"香蕉是黄色的。\",\"meaning\":\"Chuối có màu vàng.\",\"phonetic\":\"Xiāngjiāo shì huángsè de.\",\"audio_url\":\"\"},{\"text\":\"我们的看法相同。\",\"meaning\":\"Quan điểm của chúng tôi giống nhau.\",\"phonetic\":\"Wǒmen de kànfǎ xiāngtóng.\",\"audio_url\":\"\"},{\"text\":\"我相信他的话。\",\"meaning\":\"Tôi tin lời anh ấy.\",\"phonetic\":\"Wǒ xiāngxìn tā de huà.\",\"audio_url\":\"\"},{\"text\":\"他像他爸爸一样高。\",\"meaning\":\"Anh ấy cao giống như bố của mình.\",\"phonetic\":\"Tā xiàng tā bàba yīyàng gāo.\",\"audio_url\":\"\"},{\"text\":\"请小心地走路。\",\"meaning\":\"Vui lòng đi bộ cẩn thận.\",\"phonetic\":\"Qǐng xiǎoxīn de zǒulù.\",\"audio_url\":\"\"},{\"text\":\"校长在办公室工作。\",\"meaning\":\"Hiệu trưởng làm việc trong văn phòng.\",\"phonetic\":\"Xiàozhǎng zài bàngōngshì gōngzuò.\",\"audio_url\":\"\"},{\"text\":\"我买了一双新鞋。\",\"meaning\":\"Tôi đã mua một đôi giày mới.\",\"phonetic\":\"Wǒ mǎi le yī shuāng xīn xié.\",\"audio_url\":\"\"},{\"text\":\"我每天都看新闻。\",\"meaning\":\"Tôi xem tin tức mỗi ngày.\",\"phonetic\":\"Wǒ měitiān dōu kàn xīnwén.\",\"audio_url\":\"\"},{\"text\":\"这些水果很新鲜。\",\"meaning\":\"Những loại trái cây này rất tươi.\",\"phonetic\":\"Zhèxiē shuǐguǒ hěn xīnxiān.\",\"audio_url\":\"\"},{\"text\":\"我给你写了一封信。\",\"meaning\":\"Tôi đã viết cho bạn một bức thư.\",\"phonetic\":\"Wǒ gěi nǐ xiě le yī fēng xìn.\",\"audio_url\":\"\"},{\"text\":\"我的行李箱很重。\",\"meaning\":\"Vali của tôi rất nặng.\",\"phonetic\":\"Wǒ de xínglǐxiāng hěn zhòng.\",\"audio_url\":\"\"},{\"text\":\"我对中国文化有兴趣。\",\"meaning\":\"Tôi có hứng thú với văn hóa Trung Quốc.\",\"phonetic\":\"Wǒ duì Zhōngguó wénhuà yǒu xìngqù.\",\"audio_url\":\"\"},{\"text\":\"熊猫是中国的国宝。\",\"meaning\":\"Gấu trúc là báu vật quốc gia của Trung Quốc.\",\"phonetic\":\"Xióngmāo shì Zhōngguó de guóbǎo.\",\"audio_url\":\"\"},{\"text\":\"我需要一杯水。\",\"meaning\":\"Tôi cần một cốc nước.\",\"phonetic\":\"Wǒ xūyào yī bēi shuǐ.\",\"audio_url\":\"\"},{\"text\":\"你可以选择一个礼物。\",\"meaning\":\"Bạn có thể chọn một món quà.\",\"phonetic\":\"Nǐ kěyǐ xuǎnzé yī gè lǐwù.\",\"audio_url\":\"\"},{\"text\":\"他戴着一副眼镜。\",\"meaning\":\"Anh ấy đang đeo một chiếc kính.\",\"phonetic\":\"Tā dài zhe yī fù yǎnjìng.\",\"audio_url\":\"\"},{\"text\":\"老师对学生有很高的要求。\",\"meaning\":\"Giáo viên có yêu cầu rất cao đối với học sinh.\",\"phonetic\":\"Lǎoshī duì xuéshēng yǒu hěn gāo de yāoqiú.\",\"audio_url\":\"\"},{\"text\":\"我爷爷很喜欢看书。\",\"meaning\":\"Ông của tôi rất thích đọc sách.\",\"phonetic\":\"Wǒ yéye hěn xǐhuān kàn shū.\",\"audio_url\":\"\"},{\"text\":\"我一定会努力学习。\",\"meaning\":\"Tôi chắc chắn sẽ học chăm chỉ.\",\"phonetic\":\"Wǒ yídìng huì nǔlì xuéxí.\",\"audio_url\":\"\"},{\"text\":\"我们一共有五个人。\",\"meaning\":\"Chúng tôi có tổng cộng năm người.\",\"phonetic\":\"Wǒmen yígòng yǒu wǔ gè rén.\",\"audio_url\":\"\"},{\"text\":\"请等我一会儿。\",\"meaning\":\"Xin hãy đợi tôi một lát.\",\"phonetic\":\"Qǐng děng wǒ yíhuìr.\",\"audio_url\":\"\"},{\"text\":\"他们和我们一样高。\",\"meaning\":\"Họ cao bằng chúng tôi.\",\"phonetic\":\"Tāmen hé wǒmen yīyàng gāo.\",\"audio_url\":\"\"},{\"text\":\"我以后再来。\",\"meaning\":\"Tôi sẽ đến sau.\",\"phonetic\":\"Wǒ yǐhòu zài lái.\",\"audio_url\":\"\"},{\"text\":\"我以前住在北京。\",\"meaning\":\"Tôi đã từng sống ở Bắc Kinh.\",\"phonetic\":\"Wǒ yǐqián zhù zài Běijīng.\",\"audio_url\":\"\"},{\"text\":\"我以为你不来了。\",\"meaning\":\"Tôi tưởng rằng bạn không đến.\",\"phonetic\":\"Wǒ yǐwéi nǐ bù lái le.\",\"audio_url\":\"\"},{\"text\":\"这个饭馆很一般。\",\"meaning\":\"Nhà hàng này rất bình thường.\",\"phonetic\":\"Zhège fànguǎn hěn yībān.\",\"audio_url\":\"\"},{\"text\":\"他一边吃饭一边看电视。\",\"meaning\":\"Anh ấy vừa ăn vừa xem TV.\",\"phonetic\":\"Tā yìbiān chīfàn yìbiān kàn diànshì.\",\"audio_url\":\"\"},{\"text\":\"他一直在学习。\",\"meaning\":\"Anh ấy luôn luôn học tập.\",\"phonetic\":\"Tā yìzhí zài xuéxí.\",\"audio_url\":\"\"},{\"text\":\"我喜欢听音乐。\",\"meaning\":\"Tôi thích nghe nhạc.\",\"phonetic\":\"Wǒ xǐhuān tīng yīnyuè.\",\"audio_url\":\"\"},{\"text\":\"我去银行取钱。\",\"meaning\":\"Tôi đến ngân hàng rút tiền.\",\"phonetic\":\"Wǒ qù yínháng qǔ qián.\",\"audio_url\":\"\"},{\"text\":\"你应该多休息。\",\"meaning\":\"Bạn nên nghỉ ngơi nhiều hơn.\",\"phonetic\":\"Nǐ yīnggāi duō xiūxí.\",\"audio_url\":\"\"},{\"text\":\"这个电影对我影响很大。\",\"meaning\":\"Bộ phim này có ảnh hưởng lớn đối với tôi.\",\"phonetic\":\"Zhège diànyǐng duì wǒ yǐngxiǎng hěn dà.\",\"audio_url\":\"\"},{\"text\":\"请不要用手机。\",\"meaning\":\"Vui lòng không sử dụng điện thoại.\",\"phonetic\":\"Qǐng bùyào yòng shǒujī.\",\"audio_url\":\"\"},{\"text\":\"我喜欢玩游戏。\",\"meaning\":\"Tôi thích chơi trò chơi.\",\"phonetic\":\"Wǒ xǐhuān wán yóuxì.\",\"audio_url\":\"\"},{\"text\":\"他又来了。\",\"meaning\":\"Anh ấy lại đến.\",\"phonetic\":\"Tā yòu lái le.\",\"audio_url\":\"\"},{\"text\":\"他是一个有名的歌手。\",\"meaning\":\"Anh ấy là một ca sĩ nổi tiếng.\",\"phonetic\":\"Tā shì yī gè yǒumíng de gēshǒu.\",\"audio_url\":\"\"},{\"text\":\"我在路上遇到他了。\",\"meaning\":\"Tôi đã gặp anh ấy trên đường.\",\"phonetic\":\"Wǒ zài lùshàng yùdào tā le.\",\"audio_url\":\"\"},{\"text\":\"今天晚上的月亮很圆。\",\"meaning\":\"Trăng tối nay rất tròn.\",\"phonetic\":\"Jīntiān wǎnshang de yuèliàng hěn yuán.\",\"audio_url\":\"\"},{\"text\":\"天上的云很美。\",\"meaning\":\"Mây trên trời rất đẹp.\",\"phonetic\":\"Tiānshàng de yún hěn měi.\",\"audio_url\":\"\"},{\"text\":\"请站在这儿。\",\"meaning\":\"Xin hãy đứng ở đây.\",\"phonetic\":\"Qǐng zhàn zài zhèr.\",\"audio_url\":\"\"},{\"text\":\"他长得很高。\",\"meaning\":\"Anh ấy cao.\",\"phonetic\":\"Tā zhǎng de hěn gāo.\",\"audio_url\":\"\"},{\"text\":\"他很着急。\",\"meaning\":\"Anh ấy rất lo lắng.\",\"phonetic\":\"Tā hěn zhāojí.\",\"audio_url\":\"\"},{\"text\":\"我会照顾你。\",\"meaning\":\"Tôi sẽ chăm sóc bạn.\",\"phonetic\":\"Wǒ huì zhàogù nǐ.\",\"audio_url\":\"\"},{\"text\":\"这张照片很好看。\",\"meaning\":\"Bức ảnh này rất đẹp.\",\"phonetic\":\"Zhè zhāng zhàopiàn hěn hǎokàn.\",\"audio_url\":\"\"},{\"text\":\"我有一台新的照相机。\",\"meaning\":\"Tôi có một chiếc máy ảnh mới.\",\"phonetic\":\"Wǒ yǒu yī tái xīn de zhàoxiàngjī.\",\"audio_url\":\"\"},{\"text\":\"我只吃了一点儿。\",\"meaning\":\"Tôi chỉ ăn một chút.\",\"phonetic\":\"Wǒ zhǐ chī le yīdiǎnr.\",\"audio_url\":\"\"},{\"text\":\"他站在房间的中间。\",\"meaning\":\"Anh ấy đứng ở giữa phòng.\",\"phonetic\":\"Tā zhàn zài fángjiān de zhōngjiān.\",\"audio_url\":\"\"},{\"text\":\"我终于完成了作业。\",\"meaning\":\"Cuối cùng tôi đã hoàn thành bài tập.\",\"phonetic\":\"Wǒ zhōngyú wánchéng le zuòyè.\",\"audio_url\":\"\"},{\"text\":\"他喜欢这种花。\",\"meaning\":\"Anh ấy thích loại hoa này.\",\"phonetic\":\"Tā xǐhuān zhè zhǒng huā.\",\"audio_url\":\"\"},{\"text\":\"这件事很重要。\",\"meaning\":\"Việc này rất quan trọng.\",\"phonetic\":\"Zhè jiàn shì hěn zhòngyào.\",\"audio_url\":\"\"},{\"text\":\"主要问题是时间不够。\",\"meaning\":\"Vấn đề chính là không đủ thời gian.\",\"phonetic\":\"Zhǔyào wèntí shì shíjiān bù gòu.\",\"audio_url\":\"\"},{\"text\":\"周末我去公园玩。\",\"meaning\":\"Cuối tuần tôi đi công viên chơi.\",\"phonetic\":\"Zhōumò wǒ qù gōngyuán wán.\",\"audio_url\":\"\"},{\"text\":\"祝你生日快乐。\",\"meaning\":\"Chúc bạn sinh nhật vui vẻ.\",\"phonetic\":\"Zhù nǐ shēngrì kuàilè.\",\"audio_url\":\"\"},{\"text\":\"请注意安全。\",\"meaning\":\"Vui lòng chú ý an toàn.\",\"phonetic\":\"Qǐng zhùyì ānquán.\",\"audio_url\":\"\"},{\"text\":\"我需要一本字典。\",\"meaning\":\"Tôi cần một quyển từ điển.\",\"phonetic\":\"Wǒ xūyào yī běn zìdiǎn.\",\"audio_url\":\"\"},{\"text\":\"这是我自己的问题。\",\"meaning\":\"Đây là vấn đề của chính tôi.\",\"phonetic\":\"Zhè shì wǒ zìjǐ de wèntí.\",\"audio_url\":\"\"},{\"text\":\"他总是很忙。\",\"meaning\":\"Anh ấy luôn luôn bận rộn.\",\"phonetic\":\"Tā zǒngshì hěn máng.\",\"audio_url\":\"\"},{\"text\":\"最近我很忙。\",\"meaning\":\"Gần đây tôi rất bận.\",\"phonetic\":\"Zuìjìn wǒ hěn máng.\",\"audio_url\":\"\"},{\"text\":\"我已经做完作业了。\",\"meaning\":\"Tôi đã làm xong bài tập.\",\"phonetic\":\"Wǒ yǐjīng zuò wán zuòyè le.\",\"audio_url\":\"\"},{\"text\":\"这个词的作用是什么？\",\"meaning\":\"Tác dụng của từ này là gì?\",\"phonetic\":\"Zhège cí de zuòyòng shì shénme?\",\"audio_url\":\"\"}],\"words\":[],\"cards\":[],\"examples\":[]}');
INSERT INTO `lessonblock` (`id`, `lesson_id`, `type`, `seq_no`, `content`) VALUES
