INSERT INTO `lessonblock` (`id`, `lesson_id`, `type`, `seq_no`, `content`) VALUES
('b5aa798f-72b3-4ac7-9c5f-5e85ab04e2f7', '84374d9a-cbef-4d10-9b97-c5ea4295d17a', 'SENTENCE', 4, '{\"sentences\":[{\"text\":\"请你帮我吧。\",\"meaning\":\"Xin bạn giúp tôi nhé.\",\"phonetic\":\"Qǐng nǐ bāng wǒ ba.\",\"audio_url\":\"\"},{\"text\":\"他的白色衬衫很漂亮。\",\"meaning\":\"Áo sơ mi trắng của anh ấy rất đẹp.\",\"phonetic\":\"Tā de báisè chènshān hěn piàoliang.\",\"audio_url\":\"\"},{\"text\":\"我们要买一百个苹果。\",\"meaning\":\"Chúng tôi muốn mua một trăm quả táo.\",\"phonetic\":\"Wǒmen yào mǎi yī bǎi gè píngguǒ.\",\"audio_url\":\"\"},{\"text\":\"请你帮忙翻译这篇文章。\",\"meaning\":\"Xin bạn giúp dịch bài viết này.\",\"phonetic\":\"Qǐng nǐ bāngmáng fānyì zhè piān wénzhāng.\",\"audio_url\":\"\"},{\"text\":\"我每天都看报纸。\",\"meaning\":\"Tôi đọc báo mỗi ngày.\",\"phonetic\":\"Wǒ měitiān dōu kàn bàozhǐ.\",\"audio_url\":\"\"},{\"text\":\"我的家比你的家大。\",\"meaning\":\"Nhà của tôi lớn hơn nhà của bạn.\",\"phonetic\":\"Wǒ de jiā bǐ nǐ de jiā dà.\",\"audio_url\":\"\"},{\"text\":\"别忘带钥匙。\",\"meaning\":\"Đừng quên mang theo chìa khóa.\",\"phonetic\":\"Bié wàng dài yàoshi.\",\"audio_url\":\"\"},{\"text\":\"她的头发很长。\",\"meaning\":\"Tóc của cô ấy rất dài.\",\"phonetic\":\"Tā de tóufǎ hěn cháng.\",\"audio_url\":\"\"},{\"text\":\"我喜欢唱歌。\",\"meaning\":\"Tôi thích hát.\",\"phonetic\":\"Wǒ xǐhuān chànggē.\",\"audio_url\":\"\"},{\"text\":\"我们出去玩吧。\",\"meaning\":\"Chúng ta ra ngoài chơi đi.\",\"phonetic\":\"Wǒmen chūqù wán ba.\",\"audio_url\":\"\"},{\"text\":\"你穿的衣服很漂亮。\",\"meaning\":\"Quần áo bạn mặc rất đẹp.\",\"phonetic\":\"Nǐ chuān de yīfú hěn piàoliang.\",\"audio_url\":\"\"},{\"text\":\"他坐在船上。\",\"meaning\":\"Anh ấy ngồi trên thuyền.\",\"phonetic\":\"Tā zuò zài chuán shàng.\",\"audio_url\":\"\"},{\"text\":\"这是我第一次来这里。\",\"meaning\":\"Đây là lần đầu tiên tôi đến đây.\",\"phonetic\":\"Zhè shì wǒ dì yī cì lái zhèlǐ.\",\"audio_url\":\"\"},{\"text\":\"他从早上工作到晚上。\",\"meaning\":\"Anh ấy làm việc từ sáng đến tối.\",\"phonetic\":\"Tā cóng zǎoshang gōngzuò dào wǎnshang.\",\"audio_url\":\"\"},{\"text\":\"他做错了一个题。\",\"meaning\":\"Anh ấy đã làm sai một bài tập.\",\"phonetic\":\"Tā zuò cuòle yīgè tí.\",\"audio_url\":\"\"},{\"text\":\"他打篮球打得很好。\",\"meaning\":\"Anh ấy chơi bóng rổ rất giỏi.\",\"phonetic\":\"Tā dǎ lánqiú dǎ de hěn hǎo.\",\"audio_url\":\"\"},{\"text\":\"大家都很高兴。\",\"meaning\":\"Mọi người đều rất vui.\",\"phonetic\":\"Dàjiā dōu hěn gāoxìng.\",\"audio_url\":\"\"},{\"text\":\"我想去，但是没有时间。\",\"meaning\":\"Tôi muốn đi, nhưng không có thời gian.\",\"phonetic\":\"Wǒ xiǎng qù, dànshì méiyǒu shíjiān.\",\"audio_url\":\"\"},{\"text\":\"我们今天到学校了。\",\"meaning\":\"Hôm nay chúng tôi đã đến trường.\",\"phonetic\":\"Wǒmen jīntiān dào xuéxiào le.\",\"audio_url\":\"\"},{\"text\":\"你得努力学习。\",\"meaning\":\"Bạn phải cố gắng học.\",\"phonetic\":\"Nǐ děi nǔlì xuéxí.\",\"audio_url\":\"\"},{\"text\":\"我们等你来。\",\"meaning\":\"Chúng tôi đợi bạn đến.\",\"phonetic\":\"Wǒmen děng nǐ lái.\",\"audio_url\":\"\"},{\"text\":\"弟弟在玩玩具。\",\"meaning\":\"Em trai đang chơi đồ chơi.\",\"phonetic\":\"Dìdì zài wán wánjù.\",\"audio_url\":\"\"},{\"text\":\"他是第一名。\",\"meaning\":\"Anh ấy là người đứng đầu.\",\"phonetic\":\"Tā shì dì yī míng.\",\"audio_url\":\"\"},{\"text\":\"我不懂这个问题。\",\"meaning\":\"Tôi không hiểu vấn đề này.\",\"phonetic\":\"Wǒ bù dǒng zhège wèntí.\",\"audio_url\":\"\"},{\"text\":\"你对我很好。\",\"meaning\":\"Bạn đối xử tốt với tôi.\",\"phonetic\":\"Nǐ duì wǒ hěn hǎo.\",\"audio_url\":\"\"},{\"text\":\"房间里很安静。\",\"meaning\":\"Trong phòng rất yên tĩnh.\",\"phonetic\":\"Fángjiān lǐ hěn ānjìng.\",\"audio_url\":\"\"},{\"text\":\"这道菜非常好吃。\",\"meaning\":\"Món ăn này rất ngon.\",\"phonetic\":\"Zhè dào cài fēicháng hǎochī.\",\"audio_url\":\"\"},{\"text\":\"服务员请帮忙。\",\"meaning\":\"Nhân viên phục vụ, xin giúp đỡ.\",\"phonetic\":\"Fúwùyuán qǐng bāngmáng.\",\"audio_url\":\"\"},{\"text\":\"他很高。\",\"meaning\":\"Anh ấy rất cao.\",\"phonetic\":\"Tā hěn gāo.\",\"audio_url\":\"\"},{\"text\":\"请告诉我答案。\",\"meaning\":\"Xin cho tôi biết đáp án.\",\"phonetic\":\"Qǐng gàosù wǒ dá\'àn.\",\"audio_url\":\"\"},{\"text\":\"哥哥在家里。\",\"meaning\":\"Anh trai đang ở nhà.\",\"phonetic\":\"Gēge zài jiālǐ.\",\"audio_url\":\"\"},{\"text\":\"请给我一本书。\",\"meaning\":\"Xin hãy đưa cho tôi một cuốn sách.\",\"phonetic\":\"Qǐng gěi wǒ yī běn shū.\",\"audio_url\":\"\"},{\"text\":\"公共汽车很方便。\",\"meaning\":\"Xe buýt rất tiện lợi.\",\"phonetic\":\"Gōnggòng qìchē hěn fāngbiàn.\",\"audio_url\":\"\"},{\"text\":\"这个包十公斤。\",\"meaning\":\"Cái túi này mười kilogram.\",\"phonetic\":\"Zhège bāo shí gōngjīn.\",\"audio_url\":\"\"},{\"text\":\"我在公司工作。\",\"meaning\":\"Tôi làm việc ở công ty.\",\"phonetic\":\"Wǒ zài gōngsī gōngzuò.\",\"audio_url\":\"\"},{\"text\":\"这件衣服很贵。\",\"meaning\":\"Cái áo này rất đắt.\",\"phonetic\":\"Zhè jiàn yīfú hěn guì.\",\"audio_url\":\"\"},{\"text\":\"请过安检门。\",\"meaning\":\"Mời đi qua cửa an ninh.\",\"phonetic\":\"Qǐng guò ānjiǎn mén.\\\\\",\"audio_url\":\"\"},{\"text\":\"我还想要一杯水。\",\"meaning\":\"Tôi còn muốn một cốc nước.\",\"phonetic\":\"Wǒ hái xiǎng yào yī bēi shuǐ.\",\"audio_url\":\"\"},{\"text\":\"孩子们都在玩。\",\"meaning\":\"Những đứa trẻ đang chơi.\",\"phonetic\":\"Háizimen dōu zài wán.\",\"audio_url\":\"\"},{\"text\":\"这道菜很好吃。\",\"meaning\":\"Món ăn này rất ngon.\",\"phonetic\":\"Zhè dào cài hěn hǎo chī.\",\"audio_url\":\"\"},{\"text\":\"你的手机号是多少？\",\"meaning\":\"Số điện thoại của bạn là bao nhiêu?\",\"phonetic\":\"Nǐ de shǒujī hào shì duōshǎo?\",\"audio_url\":\"\"},{\"text\":\"我的车是黑色的。\",\"meaning\":\"Xe của tôi màu đen.\",\"phonetic\":\"Wǒ de chē shì hēisè de.\",\"audio_url\":\"\"},{\"text\":\"她喜欢红色的衣服。\",\"meaning\":\"Cô ấy thích quần áo màu đỏ.\",\"phonetic\":\"Tā xǐhuān hóngsè de yīfú.\",\"audio_url\":\"\"},{\"text\":\"欢迎你来我家。\",\"meaning\":\"Chào mừng bạn đến nhà tôi.\",\"phonetic\":\"Huānyíng nǐ lái wǒ jiā.\",\"audio_url\":\"\"},{\"text\":\"请回答我的问题。\",\"meaning\":\"Xin trả lời câu hỏi của tôi.\",\"phonetic\":\"Qǐng huídá wǒ de wèntí.\",\"audio_url\":\"\"},{\"text\":\"机场离这里很近。\",\"meaning\":\"Sân bay gần đây.\",\"phonetic\":\"Jīchǎng lí zhèlǐ hěn jìn.\",\"audio_url\":\"\"},{\"text\":\"我喜欢吃鸡蛋。\",\"meaning\":\"Tôi thích ăn trứng.\",\"phonetic\":\"Wǒ xǐhuān chī jīdàn.\",\"audio_url\":\"\"},{\"text\":\"这件衣服很好看。\",\"meaning\":\"Cái áo này rất đẹp.\",\"phonetic\":\"Zhè jiàn yīfú hěn hǎokàn.\",\"audio_url\":\"\"},{\"text\":\"学生们在教室里学习。\",\"meaning\":\"Học sinh đang học trong lớp học.\",\"phonetic\":\"Xuéshēngmen zài jiàoshì lǐ xuéxí.\",\"audio_url\":\"\"},{\"text\":\"姐姐比我大三岁。\",\"meaning\":\"Chị gái lớn hơn tôi ba tuổi.\",\"phonetic\":\"Jiějiě bǐ wǒ dà sān suì.\",\"audio_url\":\"\"},{\"text\":\"请介绍一下你自己。\",\"meaning\":\"Xin hãy giới thiệu về bản thân.\",\"phonetic\":\"Qǐng jièshào yīxià nǐ zìjǐ.\",\"audio_url\":\"\"},{\"text\":\"请进，别客气。\",\"meaning\":\"Mời vào, đừng khách sáo.\",\"phonetic\":\"Qǐng jìn, bié kèqì.\",\"audio_url\":\"\"},{\"text\":\"学校离我家很近。\",\"meaning\":\"Trường học gần nhà tôi.\",\"phonetic\":\"Xuéxiào lí wǒ jiā hěn jìn.\",\"audio_url\":\"\"},{\"text\":\"他就住在我家旁边。\",\"meaning\":\"Anh ấy sống ngay cạnh nhà tôi.\",\"phonetic\":\"Tā jiù zhù zài wǒ jiā pángbiān.\",\"audio_url\":\"\"},{\"text\":\"我觉得今天很热。\",\"meaning\":\"Tôi cảm thấy hôm nay rất nóng.\",\"phonetic\":\"Wǒ juéde jīntiān hěn rè.\",\"audio_url\":\"\"},{\"text\":\"我每天早上喝咖啡。\",\"meaning\":\"Tôi uống cà phê mỗi sáng.\",\"phonetic\":\"Wǒ měitiān zǎoshang hē kāfēi.\",\"audio_url\":\"\"},{\"text\":\"我们现在开始上课。\",\"meaning\":\"Bây giờ chúng ta bắt đầu học.\",\"phonetic\":\"Wǒmen xiànzài kāishǐ shàngkè.\",\"audio_url\":\"\"},{\"text\":\"我准备好考试了。\",\"meaning\":\"Tôi đã chuẩn bị sẵn sàng cho kỳ thi.\",\"phonetic\":\"Wǒ zhǔnbèi hǎo kǎoshì le.\",\"audio_url\":\"\"},{\"text\":\"可能会下雨。\",\"meaning\":\"Có thể sẽ mưa.\",\"phonetic\":\"Kěnéng huì xiàyǔ.\",\"audio_url\":\"\"},{\"text\":\"你可以坐在这里。\",\"meaning\":\"Bạn có thể ngồi ở đây.\",\"phonetic\":\"Nǐ kěyǐ zuò zài zhèlǐ.\",\"audio_url\":\"\"},{\"text\":\"我们今天有三节课。\",\"meaning\":\"Hôm nay chúng ta có ba tiết học.\",\"phonetic\":\"Wǒmen jīntiān yǒu sān jié kè.\",\"audio_url\":\"\"},{\"text\":\"他跑得很快。\",\"meaning\":\"Anh ấy chạy rất nhanh.\",\"phonetic\":\"Tā pǎo de hěn kuài.\",\"audio_url\":\"\"},{\"text\":\"祝你生日快乐。\",\"meaning\":\"Chúc bạn sinh nhật vui vẻ.\",\"phonetic\":\"Zhù nǐ shēngrì kuàilè.\",\"audio_url\":\"\"},{\"text\":\"我累了，想休息一下。\",\"meaning\":\"Tôi mệt rồi, muốn nghỉ ngơi một chút.\",\"phonetic\":\"Wǒ lèile, xiǎng xiūxí yīxià.\",\"audio_url\":\"\"},{\"text\":\"学校离我家不远。\",\"meaning\":\"Trường học không xa nhà tôi.\",\"phonetic\":\"Xuéxiào lí wǒ jiā bù yuǎn.\",\"audio_url\":\"\"},{\"text\":\"我有两个弟弟。\",\"meaning\":\"Tôi có hai em trai.\",\"phonetic\":\"Wǒ yǒu liǎng gè dìdì.\",\"audio_url\":\"\"},{\"text\":\"这条路很长。\",\"meaning\":\"Con đường này rất dài.\",\"phonetic\":\"Zhè tiáo lù hěn cháng.\",\"audio_url\":\"\"},{\"text\":\"我喜欢旅游。\",\"meaning\":\"Tôi thích du lịch.\",\"phonetic\":\"Wǒ xǐhuān lǚyóu.\",\"audio_url\":\"\"},{\"text\":\"他在商店里卖东西。\",\"meaning\":\"Anh ấy bán hàng trong cửa hàng.\",\"phonetic\":\"Tā zài shāngdiàn lǐ mài dōngxī.\",\"audio_url\":\"\"},{\"text\":\"他走得很慢。\",\"meaning\":\"Anh ấy đi rất chậm.\",\"phonetic\":\"Tā zǒu de hěn màn.\",\"audio_url\":\"\"},{\"text\":\"我今天很忙。\",\"meaning\":\"Hôm nay tôi rất bận.\",\"phonetic\":\"Wǒ jīntiān hěn máng.\",\"audio_url\":\"\"},{\"text\":\"每个人都有机会。\",\"meaning\":\"Mỗi người đều có cơ hội.\",\"phonetic\":\"Měi gèrén dōu yǒu jīhuì.\",\"audio_url\":\"\"},{\"text\":\"妹妹在唱歌。\",\"meaning\":\"Em gái đang hát.\",\"phonetic\":\"Mèimei zài chànggē.\",\"audio_url\":\"\"},{\"text\":\"他站在门口。\",\"meaning\":\"Anh ấy đứng ở cửa.\",\"phonetic\":\"Tā zhàn zài ménkǒu.\",\"audio_url\":\"\"},{\"text\":\"那个男人很高。\",\"meaning\":\"Người đàn ông đó rất cao.\",\"phonetic\":\"Nàgè nánrén hěn gāo.\",\"audio_url\":\"\"},{\"text\":\"您好，请进。\",\"meaning\":\"Xin chào, mời vào.\",\"phonetic\":\"Nín hǎo, qǐng jìn.\",\"audio_url\":\"\"},{\"text\":\"我每天早上喝牛奶。\",\"meaning\":\"Tôi uống sữa mỗi sáng.\",\"phonetic\":\"Wǒ měitiān zǎoshang hē niúnǎi.\",\"audio_url\":\"\"},{\"text\":\"那个女人是我妈妈。\",\"meaning\":\"Người phụ nữ đó là mẹ tôi.\",\"phonetic\":\"Nàgè nǚrén shì wǒ māma.\",\"audio_url\":\"\"},{\"text\":\"学校在我家旁边。\",\"meaning\":\"Trường học ở cạnh nhà tôi.\",\"phonetic\":\"Xuéxiào zài wǒ jiā pángbiān.\",\"audio_url\":\"\"},{\"text\":\"我每天早上跑步。\",\"meaning\":\"Tôi chạy bộ mỗi sáng.\",\"phonetic\":\"Wǒ měitiān zǎoshang pǎobù.\",\"audio_url\":\"\"},{\"text\":\"这件衣服很便宜。\",\"meaning\":\"Cái áo này rất rẻ.\",\"phonetic\":\"Zhè jiàn yīfú hěn piányí.\",\"audio_url\":\"\"},{\"text\":\"我买了两张电影票。\",\"meaning\":\"Tôi đã mua hai vé xem phim.\",\"phonetic\":\"Wǒ mǎile liǎng zhāng diànyǐng piào.\",\"audio_url\":\"\"},{\"text\":\"这是我的妻子。\",\"meaning\":\"Đây là vợ tôi.\",\"phonetic\":\"Zhè shì wǒ de qīzi.\",\"audio_url\":\"\"},{\"text\":\"我每天六点起床。\",\"meaning\":\"Tôi thức dậy lúc sáu giờ mỗi ngày.\",\"phonetic\":\"Wǒ měitiān liù diǎn qǐchuáng.\",\"audio_url\":\"\"},{\"text\":\"我有一千块钱。\",\"meaning\":\"Tôi có một ngàn đồng.\",\"phonetic\":\"Wǒ yǒu yīqiān kuài qián.\",\"audio_url\":\"\"},{\"text\":\"今天是晴天。\",\"meaning\":\"Hôm nay trời nắng.\",\"phonetic\":\"Jīntiān shì qíngtiān.\",\"audio_url\":\"\"},{\"text\":\"我去年去了中国。\",\"meaning\":\"Năm ngoái tôi đã đi Trung Quốc.\",\"phonetic\":\"Wǒ qùnián qùle zhōngguó.\",\"audio_url\":\"\"},{\"text\":\"请让他进来。\",\"meaning\":\"Xin hãy để anh ấy vào.\",\"phonetic\":\"Qǐng ràng tā jìnlái.\",\"audio_url\":\"\"},{\"text\":\"我每天八点上班。\",\"meaning\":\"Tôi đi làm lúc tám giờ mỗi ngày.\",\"phonetic\":\"Wǒ měitiān bā diǎn shàngbān.\",\"audio_url\":\"\"},{\"text\":\"你的身体怎么样？\",\"meaning\":\"Sức khỏe của bạn thế nào?\",\"phonetic\":\"Nǐ de shēntǐ zěnme yàng?\",\"audio_url\":\"\"},{\"text\":\"他生病了，不能来上课。\",\"meaning\":\"Anh ấy bị ốm, không thể đến lớp.\",\"phonetic\":\"Tā shēngbìng le, bùnéng lái shàngkè.\",\"audio_url\":\"\"},{\"text\":\"今天是我的生日。\",\"meaning\":\"Hôm nay là sinh nhật của tôi.\",\"phonetic\":\"Jīntiān shì wǒ de shēngrì.\",\"audio_url\":\"\"},{\"text\":\"现在我没有时间。\",\"meaning\":\"Bây giờ tôi không có thời gian.\",\"phonetic\":\"Xiànzài wǒ méiyǒu shíjiān.\",\"audio_url\":\"\"},{\"text\":\"你在做什么事情？\",\"meaning\":\"Bạn đang làm việc gì vậy?\",\"phonetic\":\"Nǐ zài zuò shénme shìqíng?\",\"audio_url\":\"\"},{\"text\":\"这块手表很贵。\",\"meaning\":\"Chiếc đồng hồ này rất đắt.\",\"phonetic\":\"Zhè kuài shǒubiǎo hěn guì.\",\"audio_url\":\"\"},{\"text\":\"我的手机没电了。\",\"meaning\":\"Điện thoại của tôi hết pin rồi.\",\"phonetic\":\"Wǒ de shǒujī méi diàn le.\",\"audio_url\":\"\"},{\"text\":\"我送你一本书。\",\"meaning\":\"Tôi tặng bạn một quyển sách.\",\"phonetic\":\"Wǒ sòng nǐ yī běn shū.\",\"audio_url\":\"\"},{\"text\":\"他很累，所以休息了。\",\"meaning\":\"Anh ấy rất mệt, nên đã nghỉ ngơi rồi.\",\"phonetic\":\"Tā hěn lèi, suǒyǐ xiūxí le.\",\"audio_url\":\"\"},{\"text\":\"它是一只可爱的小猫。\",\"meaning\":\"Nó là một chú mèo đáng yêu.\",\"phonetic\":\"Tā shì yī zhī kě\'ài de xiǎo māo.\",\"audio_url\":\"\"},{\"text\":\"我们一起踢足球吧。\",\"meaning\":\"Chúng ta cùng chơi đá bóng nhé.\",\"phonetic\":\"Wǒmen yīqǐ tī zúqiú ba.\",\"audio_url\":\"\"},{\"text\":\"这道题很难。\",\"meaning\":\"Câu hỏi này rất khó.\",\"phonetic\":\"Zhè dào tí hěn nán.\",\"audio_url\":\"\"},{\"text\":\"我喜欢跳舞。\",\"meaning\":\"Tôi thích nhảy múa.\",\"phonetic\":\"Wǒ xǐhuān tiàowǔ.\",\"audio_url\":\"\"},{\"text\":\"他在外面等你。\",\"meaning\":\"Anh ấy đang đợi bạn ở bên ngoài.\",\"phonetic\":\"Tā zài wàimiàn děng nǐ.\",\"audio_url\":\"\"},{\"text\":\"小孩子们在玩游戏。\",\"meaning\":\"Các em nhỏ đang chơi trò chơi.\",\"phonetic\":\"Xiǎo háizimen zài wán yóuxì.\",\"audio_url\":\"\"},{\"text\":\"我已经做完了作业。\",\"meaning\":\"Tôi đã làm xong bài tập.\",\"phonetic\":\"Wǒ yǐjīng zuò wán le zuòyè.\",\"audio_url\":\"\"},{\"text\":\"我晚上九点睡觉。\",\"meaning\":\"Tôi đi ngủ lúc chín giờ tối.\",\"phonetic\":\"Wǒ wǎnshàng jiǔ diǎn shuìjiào.\",\"audio_url\":\"\"},{\"text\":\"你为什么不来？\",\"meaning\":\"Tại sao bạn không đến?\",\"phonetic\":\"Nǐ wèishéme bù lái?\",\"audio_url\":\"\"},{\"text\":\"请问你叫什么名字？\",\"meaning\":\"Xin hỏi bạn tên là gì?\",\"phonetic\":\"Qǐng wèn nǐ jiào shénme míngzì?\",\"audio_url\":\"\"},{\"text\":\"这个问题很重要。\",\"meaning\":\"Vấn đề này rất quan trọng.\",\"phonetic\":\"Zhège wèntí hěn zhòngyào.\",\"audio_url\":\"\"},{\"text\":\"我喜欢吃西瓜。\",\"meaning\":\"Tôi thích ăn dưa hấu.\",\"phonetic\":\"Wǒ xǐhuān chī xīguā.\",\"audio_url\":\"\"},{\"text\":\"我希望你能来。\",\"meaning\":\"Tôi hy vọng bạn có thể đến.\",\"phonetic\":\"Wǒ xīwàng nǐ néng lái.\",\"audio_url\":\"\"},{\"text\":\"请洗手。\",\"meaning\":\"Xin rửa tay.\",\"phonetic\":\"Qǐng xǐ shǒu.\",\"audio_url\":\"\"},{\"text\":\"向左走。\",\"meaning\":\"Đi về phía bên trái.\",\"phonetic\":\"Xiàng zuǒ zǒu.\",\"audio_url\":\"\"},{\"text\":\"我每天学习一个小时。\",\"meaning\":\"Tôi học một tiếng mỗi ngày.\",\"phonetic\":\"Wǒ měitiān xuéxí yī gè xiǎoshí.\",\"audio_url\":\"\"},{\"text\":\"他在笑什么？\",\"meaning\":\"Anh ấy đang cười gì vậy?\",\"phonetic\":\"Tā zài xiào shénme?\",\"audio_url\":\"\"},{\"text\":\"我有一个新手机。\",\"meaning\":\"Tôi có một chiếc điện thoại mới.\",\"phonetic\":\"Wǒ yǒu yī gè xīn shǒujī.\",\"audio_url\":\"\"},{\"text\":\"你姓什么？\",\"meaning\":\"Họ của bạn là gì?\",\"phonetic\":\"Nǐ xìng shénme?\",\"audio_url\":\"\"},{\"text\":\"我累了，需要休息。\",\"meaning\":\"Tôi mệt rồi, cần nghỉ ngơi.\",\"phonetic\":\"Wǒ lèile, xūyào xiūxí.\",\"audio_url\":\"\"},{\"text\":\"明天会下雪。\",\"meaning\":\"Ngày mai sẽ có tuyết rơi.\",\"phonetic\":\"Míngtiān huì xià xuě.\",\"audio_url\":\"\"},{\"text\":\"你喜欢什么颜色？\",\"meaning\":\"Bạn thích màu gì?\",\"phonetic\":\"Nǐ xǐhuān shénme yánsè?\",\"audio_url\":\"\"},{\"text\":\"他的眼睛很大。\",\"meaning\":\"Mắt của anh ấy rất to.\",\"phonetic\":\"Tā de yǎnjīng hěn dà.\",\"audio_url\":\"\"},{\"text\":\"我喜欢吃羊肉。\",\"meaning\":\"Tôi thích ăn thịt cừu.\",\"phonetic\":\"Wǒ xǐhuān chī yángròu.\",\"audio_url\":\"\"},{\"text\":\"我要一杯水。\",\"meaning\":\"Tôi muốn một cốc nước.\",\"phonetic\":\"Wǒ yào yī bēi shuǐ.\",\"audio_url\":\"\"},{\"text\":\"我生病了，要吃药。\",\"meaning\":\"Tôi bị ốm, cần uống thuốc.\",\"phonetic\":\"Wǒ shēngbìng le, yào chī yào.\",\"audio_url\":\"\"},{\"text\":\"他也喜欢游泳。\",\"meaning\":\"Anh ấy cũng thích bơi lội.\",\"phonetic\":\"Tā yě xǐhuān yóuyǒng.\",\"audio_url\":\"\"},{\"text\":\"我已经吃过饭了。\",\"meaning\":\"Tôi đã ăn cơm rồi.\",\"phonetic\":\"Wǒ yǐjīng chī guò fàn le.\",\"audio_url\":\"\"},{\"text\":\"我们一起去看电影吧。\",\"meaning\":\"Chúng ta cùng đi xem phim nhé.\",\"phonetic\":\"Wǒmen yīqǐ qù kàn diànyǐng ba.\",\"audio_url\":\"\"},{\"text\":\"这是什么意思？\",\"meaning\":\"Điều này có nghĩa là gì?\",\"phonetic\":\"Zhè shì shénme yìsi?\",\"audio_url\":\"\"},{\"text\":\"今天是阴天。\",\"meaning\":\"Hôm nay là ngày trời âm u.\",\"phonetic\":\"Jīntiān shì yīntiān.\",\"audio_url\":\"\"},{\"text\":\"因为下雨，我不去跑步。\",\"meaning\":\"Vì trời mưa, tôi không đi chạy bộ.\",\"phonetic\":\"Yīnwèi xiàyǔ, wǒ bú qù pǎobù.\",\"audio_url\":\"\"},{\"text\":\"我喜欢游泳。\",\"meaning\":\"Tôi thích bơi lội.\",\"phonetic\":\"Wǒ xǐhuān yóuyǒng.\",\"audio_url\":\"\"},{\"text\":\"他坐在我右边。\",\"meaning\":\"Anh ấy ngồi bên phải tôi.\",\"phonetic\":\"Tā zuò zài wǒ yòubiān.\",\"audio_url\":\"\"},{\"text\":\"我们晚饭吃鱼。\",\"meaning\":\"Chúng tôi ăn cá vào bữa tối.\",\"phonetic\":\"Wǒmen wǎnfàn chī yú.\",\"audio_url\":\"\"},{\"text\":\"这本书要十元。\",\"meaning\":\"Quyển sách này giá mười đồng.\",\"phonetic\":\"Zhè běn shū yào shí yuán.\",\"audio_url\":\"\"},{\"text\":\"他家离学校很远。\",\"meaning\":\"Nhà anh ấy cách xa trường học.\",\"phonetic\":\"Tā jiā lí xuéxiào hěn yuǎn.\",\"audio_url\":\"\"},{\"text\":\"我每天都运动。\",\"meaning\":\"Tôi tập thể dục mỗi ngày.\",\"phonetic\":\"Wǒ měitiān dōu yùndòng.\",\"audio_url\":\"\"},{\"text\":\"请再说一遍。\",\"meaning\":\"Xin hãy nói lại một lần nữa.\",\"phonetic\":\"Qǐng zài shuō yī biàn.\",\"audio_url\":\"\"},{\"text\":\"我每天早上六点起床。\",\"meaning\":\"Tôi dậy lúc sáu giờ sáng mỗi ngày.\",\"phonetic\":\"Wǒ měitiān zǎoshang liù diǎn qǐchuáng.\",\"audio_url\":\"\"},{\"text\":\"这是一张照片。\",\"meaning\":\"Đây là một tấm ảnh.\",\"phonetic\":\"Zhè shì yī zhāng zhàopiàn.\",\"audio_url\":\"\"},{\"text\":\"这是我的丈夫。\",\"meaning\":\"Đây là chồng tôi.\",\"phonetic\":\"Zhè shì wǒ de zhàngfu.\",\"audio_url\":\"\"},{\"text\":\"我在找我的钥匙。\",\"meaning\":\"Tôi đang tìm chìa khóa của mình.\",\"phonetic\":\"Wǒ zài zhǎo wǒ de yàoshi.\",\"audio_url\":\"\"},{\"text\":\"他在吃着饭呢。\",\"meaning\":\"Anh ấy đang ăn cơm.\",\"phonetic\":\"Tā zài chī zhe fàn ne.\",\"audio_url\":\"\"},{\"text\":\"这个苹果真好吃。\",\"meaning\":\"Quả táo này thật ngon.\",\"phonetic\":\"Zhège píngguǒ zhēn hào chī.\",\"audio_url\":\"\"},{\"text\":\"妈妈正在打电话。\",\"meaning\":\"Mẹ đang gọi điện thoại.\",\"phonetic\":\"Māma zhèngzài dǎ diànhuà.\",\"audio_url\":\"\"},{\"text\":\"我知道他是谁。\",\"meaning\":\"Tôi biết anh ấy là ai.\",\"phonetic\":\"Wǒ zhīdào tā shì shéi.\",\"audio_url\":\"\"},{\"text\":\"我正在准备考试。\",\"meaning\":\"Tôi đang chuẩn bị cho kỳ thi.\",\"phonetic\":\"Wǒ zhèngzài zhǔnbèi kǎoshì.\",\"audio_url\":\"\"},{\"text\":\"他骑自行车去上班。\",\"meaning\":\"Anh ấy đi làm bằng xe đạp.\",\"phonetic\":\"Tā qí zìxíngchē qù shàngbān.\",\"audio_url\":\"\"},{\"text\":\"我们一起走吧。\",\"meaning\":\"Chúng ta cùng đi nhé.\",\"phonetic\":\"Wǒmen yīqǐ zǒu ba.\",\"audio_url\":\"\"},{\"text\":\"这是我最喜欢的书。\",\"meaning\":\"Đây là cuốn sách tôi thích nhất.\",\"phonetic\":\"Zhè shì wǒ zuì xǐhuān de shū.\",\"audio_url\":\"\"},{\"text\":\"他坐在我左边。\",\"meaning\":\"Anh ấy ngồi bên trái tôi.\",\"phonetic\":\"Tā zuò zài wǒ zuǒbiān.\",\"audio_url\":\"\"}],\"words\":[],\"cards\":[],\"examples\":[]}'),
